/* Reasoning GP — Articles data (batch 13: H topics, part 2)
   NHS conditions A–Z (letter H) not already covered. RCGP/SCA examiner depth.
   NICE NG12 (May 2025) 2WW pathways stated explicitly where relevant. */
(function(){
  const A = (window.RGP_ARTICLES = window.RGP_ARTICLES || []);
  A.push(

  { id:'palpitations', title:'Heart palpitations', category:'Cardiovascular & Renal', icon:'🫀',
    overview:'An awareness of the heartbeat — fast, forceful, irregular or skipped. Most palpitations are benign (ectopics, sinus tachycardia, anxiety), but the task is to identify the minority with a dangerous arrhythmia or structural/electrical heart disease, guided by the history, ECG, and crucially the company the palpitations keep (syncope, family history).',
    features:[
      'Characterise the palpitation: fast vs slow, regular vs irregular, sudden vs gradual onset/offset, duration, and triggers (exercise, caffeine, alcohol, stress)',
      'Benign causes: ectopic beats (a "skipped"/"thudding" beat, often at rest, settling with exercise), sinus tachycardia, anxiety, caffeine, and stimulants',
      'Arrhythmias: atrial fibrillation (irregularly irregular), SVT (sudden-onset regular fast palpitations), and ventricular arrhythmias (dangerous)',
      'RED FLAGS: palpitations with syncope/presyncope, chest pain or breathlessness, occurring on exertion, a family history of sudden cardiac death or inherited cardiac conditions, or known structural heart disease',
      'Consider non-cardiac drivers: thyrotoxicosis, anaemia, fever, hypoglycaemia, drugs, and the menopause',
      'Investigations: a 12-lead ECG (look for arrhythmia, pre-excitation/WPW, long QT, conduction disease), bloods (FBC, TFTs, U&E), and ambulatory/event monitoring to capture intermittent symptoms'],
    management:[
      'Take a careful history and perform a 12-lead ECG; check FBC, thyroid function and electrolytes',
      'Identify and act on red flags (syncope, exertional symptoms, family history of sudden death, abnormal ECG) → urgent cardiology',
      'Capture intermittent palpitations with ambulatory monitoring (Holter or event/patch recorder) matched to symptom frequency',
      'Benign ectopics/sinus tachycardia: reassure, and advise reducing caffeine, alcohol and stimulants; manage anxiety where relevant',
      'Manage atrial fibrillation per its pathway (rate/rhythm control and anticoagulation assessment)',
      'Teach vagal manoeuvres for recurrent SVT and refer for assessment (ablation is curative for many)',
      'Treat non-cardiac causes (thyrotoxicosis, anaemia)',
      'Advise patients to seek urgent help for palpitations with chest pain, breathlessness, or blackout, and provide safety-netting'],
    referral:[
      'Palpitations with syncope/presyncope, chest pain, or on exertion → urgent cardiology',
      'Abnormal ECG (pre-excitation/WPW, long QT, conduction disease, sustained arrhythmia) or family history of sudden cardiac death → cardiology',
      'Documented SVT/sustained arrhythmia → cardiology (consider ablation)',
      'Haemodynamically unstable arrhythmia → emergency admission'],
    source:'NICE CKS — Palpitations' },

  { id:'heatstroke', title:'Heat exhaustion and heatstroke', category:'General', icon:'🌡️',
    overview:'A spectrum of heat illness from heat exhaustion (an early, reversible state) to heatstroke (a life-threatening emergency with core temperature typically >40°C and central nervous system dysfunction). Rapid recognition and aggressive cooling save lives; the vulnerable (elderly, very young, chronically ill) are most at risk.',
    features:[
      'Heat exhaustion: heavy sweating, headache, dizziness, nausea, cramps, fatigue, thirst, and a fast/weak pulse — the person is distressed but mentally intact, and the core temperature is normal/mildly raised',
      'HEATSTROKE: a high core temperature (typically >40°C) with central nervous system dysfunction — confusion, agitation, seizures, or loss of consciousness — a medical emergency',
      'Skin in heatstroke may be hot and dry (classic) or sweaty (exertional); there may be tachycardia, hypotension and rapid breathing',
      'Classic heatstroke affects vulnerable people in heatwaves (elderly, infants, chronic illness, certain drugs); exertional heatstroke affects athletes/workers/military in the heat',
      'Complications: rhabdomyolysis, acute kidney injury, DIC, and multi-organ failure',
      'Risk factors/drugs: dehydration, alcohol, anticholinergics, diuretics, antipsychotics, and conditions impairing thermoregulation'],
    management:[
      'Heat exhaustion: move to a cool place, lie down and elevate the legs, remove excess clothing, cool the skin (cool water/fans), and give fluids (oral rehydration) — recovery should occur within ~30 minutes',
      'If the person does not improve within 30 minutes, or shows any features of heatstroke, treat as an emergency',
      'HEATSTROKE is a 999 emergency — start rapid cooling immediately while arranging transfer: move to shade/cool, remove clothing, and use aggressive external cooling (cold water immersion if available, or wetting the skin with cool water plus fanning, ice packs to neck/axillae/groin)',
      'Do not give antipyretics (paracetamol/ibuprofen) — they do not work in heatstroke and may harm',
      'Manage airway/breathing/circulation, give IV fluids, and treat complications (seizures, rhabdomyolysis, AKI) in hospital',
      'Identify and review contributing medications',
      'Prevent recurrence: advise on hydration, avoiding peak heat, appropriate clothing, and checking on vulnerable people during heatwaves',
      'Public-health heatwave planning for at-risk patients'],
    referral:[
      'Heatstroke (high temperature + confusion/altered consciousness/seizures) → 999 emergency with immediate cooling started',
      'Heat exhaustion not improving within 30 minutes, or in a vulnerable person → urgent assessment',
      'Complications (seizures, collapse, reduced urine output, abnormal bleeding) → emergency admission',
      'Recurrent heat illness → review medications and risk factors'],
    source:'NICE CKS / UKHSA Heat-Health guidance' },

  { id:'hepatitis-a', title:'Hepatitis A', category:'Infectious diseases', icon:'🦠',
    overview:'An acute, faecal-orally transmitted viral hepatitis, usually self-limiting and never chronic. It is associated with travel to endemic areas and contaminated food/water. The main issues are supportive care, recognising the rare fulminant case, public-health notification, and prevention through vaccination and hygiene.',
    features:[
      'A prodrome of fever, malaise, nausea, anorexia and right-upper-quadrant discomfort, followed by jaundice, dark urine and pale stools',
      'Often mild or asymptomatic in young children; more symptomatic in adults',
      'Transmission is faecal-oral — contaminated food/water, travel to endemic regions, household/sexual contact, and outbreaks (including in men who have sex with men)',
      'It is an acute illness only — hepatitis A does NOT cause chronic infection or chronic liver disease',
      'Rarely, fulminant hepatic failure occurs (higher risk in older adults or those with pre-existing liver disease)',
      'Diagnosis: hepatitic LFTs and hepatitis A IgM serology; it is a notifiable disease'],
    management:[
      'Supportive care: rest, hydration, antiemetics if needed, and avoidance of alcohol and hepatotoxic drugs until recovered',
      'Most recover fully over weeks; reassure about the absence of chronic infection',
      'Monitor for signs of fulminant liver failure (worsening jaundice, confusion/encephalopathy, bleeding) and admit urgently if suspected',
      'Advise on hygiene to prevent spread (hand-washing, food handling) and exclusion (e.g. food handlers, healthcare/childcare workers per guidance, usually until ~7 days after jaundice onset)',
      'Notify the health protection team — hepatitis A is notifiable, and contacts may need post-exposure vaccination/immunoglobulin',
      'Offer hepatitis A vaccination for prevention to travellers to endemic areas and other at-risk groups (e.g. chronic liver disease, MSM, occupational risk)',
      'Avoid alcohol and review medications metabolised by the liver during the illness',
      'Arrange follow-up to confirm resolution of liver function'],
    referral:[
      'Suspected fulminant hepatic failure (encephalopathy, coagulopathy, deepening jaundice) → emergency admission/hepatology',
      'Severe illness or significant dehydration → admission',
      'Notify public health (notifiable) and arrange contact management/prophylaxis',
      'Pre-existing liver disease with acute hepatitis A → lower threshold for specialist input'],
    source:'UKHSA / Green Book / NICE CKS — Hepatitis A' },

  { id:'hepatitis-b', title:'Hepatitis B', category:'Infectious diseases', icon:'🦠',
    overview:'A blood-borne viral infection that can be acute or chronic. Chronic hepatitis B causes progressive liver damage, cirrhosis and hepatocellular carcinoma. It is vaccine-preventable, and effective antiviral treatment plus surveillance markedly reduce complications — so detection, vaccination and specialist linkage are key.',
    features:[
      'Acute infection: often asymptomatic, or a hepatitic illness (malaise, nausea, jaundice); most adults clear it, but a minority develop chronic infection',
      'Chronic hepatitis B: usually asymptomatic for years, detected by screening/serology, with a long-term risk of cirrhosis and hepatocellular carcinoma',
      'Transmission: blood/body fluids — mother-to-child (vertical, the major route worldwide), sexual, sharing needles, and unscreened blood/medical exposure',
      'Vertical and early-childhood infection carries a high risk of chronicity',
      'At-risk groups: people from endemic countries, household/sexual contacts of carriers, people who inject drugs, and infants of infected mothers',
      'Diagnosis/monitoring: serology (HBsAg, anti-HBc, HBeAg/anti-HBe), HBV DNA viral load, LFTs, and fibrosis assessment'],
    management:[
      'Screen at-risk groups and in pregnancy (antenatal screening protects the baby — infected mothers’ infants receive timely vaccination ± immunoglobulin)',
      'Refer chronic hepatitis B to hepatology/infectious diseases for assessment, monitoring and treatment',
      'Antiviral therapy (e.g. tenofovir, entecavir) for those meeting criteria suppresses the virus and reduces progression — specialist-led',
      'Arrange hepatocellular carcinoma surveillance (6-monthly liver ultrasound ± AFP) for at-risk patients (cirrhosis, and certain chronic carriers), and monitor liver function/fibrosis',
      'Vaccinate at-risk contacts and offer vaccination per the programme; ensure household/sexual contacts are tested and vaccinated',
      'Advise on reducing transmission (safer sex, not sharing needles/razors, disclosing to healthcare/dental providers) and avoid alcohol/hepatotoxins',
      'Notify public health (hepatitis B is notifiable) and coordinate contact management',
      'Provide vaccination against hepatitis A and other supportive measures for those with chronic liver disease'],
    referral:[
      'Chronic hepatitis B → hepatology/infectious diseases for monitoring and antiviral treatment',
      'Cirrhosis or other at-risk status → 6-monthly hepatocellular carcinoma surveillance; a suspicious liver lesion → urgent referral (NICE NG12)',
      'Pregnancy with hepatitis B → coordinate antenatal/neonatal pathway (infant immunoprophylaxis)',
      'Acute liver failure → emergency hepatology; notify public health'],
    source:'NICE / UKHSA / Green Book — Hepatitis B' },

  { id:'hepatitis-c', title:'Hepatitis C', category:'Infectious diseases', icon:'🦠',
    overview:'A blood-borne viral infection that frequently becomes chronic and silently progresses to cirrhosis and hepatocellular carcinoma over decades. It is now curable in most people with short courses of direct-acting antivirals — making case-finding in at-risk groups and linkage to treatment a major opportunity.',
    features:[
      'Acute infection is usually asymptomatic; the majority develop chronic infection, which is also typically silent for years',
      'Chronic hepatitis C: often detected by screening or incidentally (abnormal LFTs), progressing over decades to cirrhosis, liver failure and hepatocellular carcinoma',
      'Transmission is predominantly blood-borne: sharing injecting equipment (the major route in the UK), unscreened blood products (historical), needlestick, and (less commonly) sexual/vertical',
      'Extrahepatic associations: cryoglobulinaemia, glomerulonephritis, and porphyria cutanea tarda',
      'At-risk groups to test: people who inject drugs (current/past), recipients of blood products before screening, people from high-prevalence countries, and those with HIV',
      'Diagnosis: hepatitis C antibody (exposure), then HCV RNA (confirms current infection); assess genotype, liver fibrosis and function'],
    management:[
      'Actively case-find and test at-risk groups (especially people who have ever injected drugs) — most infection is undiagnosed and now curable',
      'Confirm current infection with HCV RNA (antibody positive but RNA negative indicates past/cleared infection) and assess liver fibrosis',
      'Refer to hepatology/specialist hepatitis services for treatment — direct-acting antivirals cure the great majority with short, well-tolerated oral courses',
      'Arrange hepatocellular carcinoma surveillance (6-monthly ultrasound ± AFP) for those with cirrhosis, even after cure',
      'Provide harm reduction: needle-and-syringe programmes, safer-injecting advice, and treatment of substance misuse; advise on preventing transmission',
      'Vaccinate against hepatitis A and B, avoid alcohol/hepatotoxins, and manage comorbidity',
      'Note that cure does not confer immunity — reinfection is possible, so continue harm reduction and re-test those at ongoing risk',
      'Notify public health (notifiable) and support linkage/retention in care'],
    referral:[
      'Confirmed chronic hepatitis C (HCV RNA positive) → hepatitis/hepatology service for direct-acting antiviral treatment',
      'Cirrhosis → 6-monthly hepatocellular carcinoma surveillance (continue after cure); suspicious lesion → urgent referral (NICE NG12)',
      'Decompensated liver disease or extrahepatic complications → urgent specialist care',
      'Ongoing injecting/risk → harm-reduction and substance-misuse services; notify public health'],
    source:'NICE / UKHSA — Hepatitis C' },

  { id:'hernia', title:'Hernia (inguinal, femoral and other abdominal wall hernias)', category:'General', icon:'🩹',
    overview:'A protrusion of a viscus (often bowel) through a defect in the abdominal wall. Most are inguinal and present as a reducible lump; the critical complications are obstruction and strangulation, where the blood supply is compromised — a surgical emergency. Recognising the irreducible, tender hernia is the key skill.',
    features:[
      'A lump that appears/enlarges on standing, coughing or straining and reduces on lying down; may cause dragging discomfort',
      'Inguinal hernia (commonest, especially in men): a groin lump above the inguinal ligament; femoral hernia (commoner in women): below and lateral to the pubic tubercle and at higher risk of strangulation',
      'Other types: umbilical/paraumbilical, incisional (at a previous surgical scar), epigastric, and (in infants) umbilical hernias that usually resolve',
      'OBSTRUCTION/STRANGULATION red flags: a painful, tender, irreducible (often tense) lump, with vomiting, abdominal distension, and signs of bowel obstruction; the overlying skin may become red — this is an emergency',
      'Risk factors: increasing age, male sex, chronic cough, constipation/straining, heavy lifting, obesity, and previous surgery',
      'Diagnosis is clinical; ultrasound or CT helps for uncertain or complex cases'],
    management:[
      'Assess reducibility, tenderness, and signs of obstruction/strangulation; examine the groin (standing and lying) and abdomen',
      'A strangulated/obstructed hernia (painful, tender, irreducible, with vomiting/obstruction) is a surgical emergency — admit immediately',
      'For uncomplicated, reducible hernias: refer for elective surgical repair, especially symptomatic or enlarging hernias',
      'Femoral hernias should generally be repaired promptly (even if asymptomatic) due to the higher strangulation risk',
      'Inguinal hernias: discuss elective repair; watchful waiting may be reasonable for small, minimally symptomatic hernias in some patients, with clear safety-netting',
      'Most infantile umbilical hernias resolve spontaneously by a few years of age — reassure, and refer if persistent/large or complicated',
      'Advise all patients on the red flags of strangulation and to seek emergency care if the hernia becomes painful, tender, or irreducible',
      'Address contributory factors (constipation, chronic cough, weight) where possible'],
    referral:[
      'Strangulated/obstructed hernia (painful, tender, irreducible lump ± obstruction) → emergency surgical admission',
      'Femoral hernia → prompt surgical referral (high strangulation risk)',
      'Symptomatic/enlarging inguinal or other hernia → elective surgical referral',
      'Persistent/large or complicated infantile umbilical hernia → paediatric surgery'],
    source:'NICE CKS — Hernias / surgical guidance' },

  { id:'hypertension', title:'High blood pressure (hypertension)', category:'Cardiovascular & Renal', icon:'🩺',
    overview:'Persistently raised arterial blood pressure — a major, usually symptomless, modifiable risk factor for stroke, heart attack, heart failure, kidney disease and dementia. The primary-care role is accurate diagnosis (with out-of-office readings), risk assessment, and achieving target control to prevent cardiovascular events.',
    features:[
      'Usually asymptomatic and detected on screening/opportunistic measurement — "the silent killer"',
      'Diagnosis requires confirmation with ambulatory (ABPM) or home (HBPM) monitoring, as clinic readings overestimate (white-coat effect)',
      'Stages (per NICE NG136): Stage 1 (clinic ≥140/90, ABPM/HBPM ≥135/85), Stage 2 (clinic ≥160/100, ABPM/HBPM ≥150/95), and severe (clinic ≥180/120)',
      'Most is primary (essential); consider SECONDARY causes (renal disease, primary hyperaldosteronism, phaeochromocytoma, Cushing’s, coarctation, drugs) in the young, resistant, or those with suggestive features',
      'ACCELERATED/MALIGNANT hypertension: BP ≥180/120 with signs of end-organ damage (retinal haemorrhages/papilloedema, new confusion, chest pain, heart failure, AKI) — an emergency',
      'Assess for end-organ damage and overall cardiovascular risk: bloods (renal function, HbA1c, lipids), urine ACR, ECG, and fundi'],
    management:[
      'Confirm the diagnosis with ABPM/HBPM (except in severe hypertension with end-organ damage, which needs same-day action)',
      'Assess cardiovascular risk (QRISK), screen for end-organ damage and diabetes, and consider/ exclude secondary causes where indicated',
      'Lifestyle first and throughout: reduce salt, healthy diet, weight loss, regular exercise, limit alcohol and caffeine, and stop smoking',
      'Offer drug treatment per NICE NG136 thresholds: all Stage 2, and Stage 1 with raised cardiovascular risk/end-organ damage/diabetes/established disease (and consider in younger patients)',
      'Start treatment by age/ethnicity: ACE inhibitor/ARB for those under 55 (not of Black African/Caribbean ancestry), or a calcium-channel blocker for those 55+ or of Black African/Caribbean ancestry; step up to combinations and add a thiazide-like diuretic, then a fourth agent (e.g. spironolactone) for resistant hypertension',
      'Aim for target BP (e.g. <140/90 clinic / <135/85 HBPM under 80; relaxed targets in the over-80s) and monitor U&E with ACEi/ARB/diuretics',
      'Treat the whole cardiovascular risk profile (statins, diabetes, etc.) and review regularly',
      'Recognise and act urgently on accelerated/malignant hypertension and hypertensive emergencies'],
    referral:[
      'Accelerated/malignant hypertension (≥180/120 with retinal haemorrhages/papilloedema or other acute end-organ damage) → same-day specialist assessment',
      'Suspected phaeochromocytoma (labile BP, sweating, palpitations, headaches) → urgent referral',
      'Suspected secondary hypertension, resistant hypertension, or hypertension in the young → specialist (endocrine/renal/cardiology)',
      'Hypertension in pregnancy → obstetric/maternal-medicine pathway'],
    source:'NICE NG136 (Hypertension in adults)' },

  { id:'high-cholesterol', title:'High cholesterol (and lipid disorders)', category:'Cardiovascular & Renal', icon:'🩸',
    overview:'Raised blood lipids are a major, modifiable driver of atherosclerotic cardiovascular disease. Most is multifactorial (diet, lifestyle, genetics), but recognising familial hypercholesterolaemia — a common, under-diagnosed inherited cause of premature heart disease — is a specific and important task. Management is risk-based, centred on statins.',
    features:[
      'Usually asymptomatic and detected on a lipid profile done for cardiovascular risk assessment',
      'A non-fasting lipid profile (total, HDL, non-HDL cholesterol and triglycerides) is used for risk assessment',
      'FAMILIAL HYPERCHOLESTEROLAEMIA (FH): suspect with very high cholesterol (e.g. total >7.5 mmol/L or LDL very high), a personal/family history of premature coronary disease, or physical signs (tendon xanthomata, corneal arcus/xanthelasma in the young)',
      'Severe hypertriglyceridaemia carries a risk of acute pancreatitis',
      'Secondary causes/contributors: hypothyroidism, diabetes, obesity, excess alcohol, chronic kidney/liver disease, and certain drugs',
      'Assessment: lipid profile, cardiovascular risk score (QRISK), and exclusion of secondary causes (TFTs, HbA1c, renal/liver function)'],
    management:[
      'Use a cardiovascular risk assessment (QRISK) to guide primary prevention; everyone benefits from lifestyle measures',
      'Lifestyle: a heart-healthy diet (reduce saturated fat, increase fibre), weight management, physical activity, reduce alcohol, and stop smoking',
      'Offer a statin (atorvastatin 20 mg) for primary prevention where 10-year cardiovascular risk is ≥10%, and high-intensity statins (atorvastatin 80 mg) for secondary prevention (established cardiovascular disease)',
      'Check baseline lipids, liver function and (per guidance) reassess lipid response, aiming for a ≥40% reduction in non-HDL cholesterol; add ezetimibe and consider further agents (e.g. PCSK9 inhibitors, specialist-led) if targets are not met',
      'Identify and refer suspected familial hypercholesterolaemia for diagnosis, specialist treatment, and cascade testing of relatives',
      'Treat secondary causes (e.g. hypothyroidism) and manage very high triglycerides (lifestyle, fibrates, reduce alcohol) to prevent pancreatitis',
      'Address the whole cardiovascular risk profile (BP, diabetes) and support adherence',
      'Review and monitor treatment, and counsel on the benefits and manage any statin side effects'],
    referral:[
      'Suspected familial hypercholesterolaemia (very high cholesterol, premature CVD family history, tendon xanthomata) → specialist lipid clinic + cascade testing',
      'Failure to reach lipid targets on statin ± ezetimibe → lipid clinic (consider PCSK9 inhibitors)',
      'Severe hypertriglyceridaemia (pancreatitis risk) → specialist input',
      'Statin intolerance or complex lipid disorders → lipid specialist'],
    source:'NICE NG238 (Cardiovascular disease: risk reduction) / NICE CG71 (FH)' },

  { id:'hiv', title:'HIV and AIDS', category:'Infectious diseases', icon:'🦠',
    overview:'Human immunodeficiency virus progressively destroys CD4 immune cells; untreated it leads to AIDS and opportunistic infections/cancers. With modern antiretroviral therapy it is a manageable chronic condition with near-normal life expectancy, and effective treatment makes the virus untransmittable (U=U). Testing, early diagnosis and prevention are the priorities.',
    features:[
      'Primary HIV (seroconversion): a glandular-fever-like illness — fever, sore throat, rash, lymphadenopathy, myalgia — weeks after exposure (often missed)',
      'A long asymptomatic period follows; without treatment, progressive immunosuppression leads to opportunistic infections and AIDS-defining illnesses',
      'Indicator conditions prompting an HIV test: unexplained weight loss/lymphadenopathy, recurrent/severe infections, oral candida/hairy leukoplakia, shingles in the young, certain cancers, TB, and unexplained blood abnormalities',
      'AIDS: severe immunosuppression with opportunistic infections (e.g. Pneumocystis pneumonia, cerebral toxoplasmosis) and certain cancers (e.g. Kaposi sarcoma, lymphoma)',
      'Transmission: sexual, blood (sharing needles), and vertical (mother-to-child); prevented by treatment, condoms, PrEP and PEP',
      'Diagnosis: a 4th-generation HIV antibody/antigen blood test (with appropriate window-period advice); offer testing widely and normalise it'],
    management:[
      'Test widely and opportunistically — offer HIV testing to anyone with an indicator condition, in higher-prevalence areas, and as part of sexual-health/antenatal screening; normalise testing to enable early diagnosis',
      'Refer all newly diagnosed patients promptly to HIV specialist services',
      'Antiretroviral therapy (ART) is recommended for everyone with HIV, started early — it restores immune function, gives near-normal life expectancy, and renders the virus untransmittable (undetectable = untransmittable, U=U)',
      'Support adherence (lifelong, daily), monitor viral load/CD4, and manage drug interactions (HIV drugs interact with many medicines — always check before co-prescribing)',
      'Provide prevention: pre-exposure prophylaxis (PrEP) for those at risk, post-exposure prophylaxis (PEP) after significant exposure, condoms, and partner notification',
      'In pregnancy, ART and an appropriate delivery/infant-feeding plan virtually eliminate vertical transmission',
      'Manage comorbidity and health promotion (cardiovascular risk, vaccinations — avoid live vaccines if significantly immunosuppressed, cancer screening, mental health, bone health)',
      'Address stigma, confidentiality, and psychological/social support'],
    referral:[
      'Newly diagnosed HIV → HIV specialist service (start ART, monitoring)',
      'Suspected seroconversion illness or an HIV indicator condition → test and refer',
      'Significant exposure → urgent assessment for post-exposure prophylaxis (PEP — time-critical, ideally within 72 hours)',
      'Pregnancy with HIV → specialist HIV-obstetric care; suspected opportunistic infection → urgent specialist/admission'],
    source:'BHIVA / NICE CKS / UKHSA — HIV' },

  { id:'hives', title:'Hives (urticaria)', category:'Dermatology', icon:'🌸',
    overview:'An itchy, raised wheal-and-flare rash from dermal mast-cell histamine release, often with angioedema. Acute urticaria is common and usually self-limiting; chronic urticaria (>6 weeks) is frequently spontaneous and not allergic. The key safety task is recognising anaphylaxis and significant angioedema.',
    features:[
      'Itchy, raised, pink/white wheals (hives) that are transient — individual lesions come and go within 24 hours, often migrating',
      'May be accompanied by angioedema (deeper swelling of lips, eyelids, tongue, hands)',
      'Acute urticaria (<6 weeks): often triggered by infection (especially in children), foods, drugs (e.g. NSAIDs, antibiotics), or insect stings — though a cause is frequently not found',
      'Chronic urticaria (≥6 weeks): mostly chronic spontaneous urticaria (often autoimmune, not allergic), or inducible (physical triggers — pressure, cold, heat, exercise, sunlight)',
      'RED FLAGS for anaphylaxis: rapidly progressive swelling with breathing difficulty/wheeze/stridor, throat tightness, hypotension/collapse — a medical emergency',
      'Angioedema without urticaria (especially recurrent, or with a family history, or related to ACE inhibitors) raises other causes (e.g. ACE-inhibitor or hereditary angioedema)'],
    management:[
      'Recognise and treat anaphylaxis immediately (intramuscular adrenaline, ABC) — urticaria/angioedema with airway/breathing/circulation compromise is an emergency',
      'Identify and remove triggers where possible (suspect drugs such as NSAIDs/antibiotics, foods, infection); stop ACE inhibitors if implicated in angioedema',
      'First-line treatment is a regular non-sedating antihistamine (e.g. cetirizine); the dose can be increased (up to fourfold, specialist-guided) for chronic urticaria',
      'A short course of oral corticosteroid can help a severe acute flare; avoid long-term steroids',
      'Reassure in chronic spontaneous urticaria that it is usually not allergic and tends to remit over time; provide a self-management plan',
      'Refer chronic urticaria not controlled on up-dosed antihistamines for specialist treatment (e.g. omalizumab) and refer for allergy assessment where a specific allergen/anaphylaxis is suspected',
      'Investigate atypical features (systemic symptoms, lesions lasting >24 hours/bruising — consider urticarial vasculitis) appropriately',
      'For recurrent angioedema without wheals, consider hereditary/ACE-inhibitor angioedema and refer/adjust drugs accordingly'],
    referral:[
      'Anaphylaxis or significant airway-threatening angioedema → emergency (adrenaline, 999); refer to allergy after an anaphylaxis episode',
      'Chronic urticaria uncontrolled on up-dosed antihistamines → dermatology/immunology (e.g. omalizumab)',
      'Suspected specific allergy/anaphylactic trigger → allergy/immunology',
      'Suspected hereditary angioedema or urticarial vasculitis → immunology/dermatology'],
    source:'NICE CKS — Urticaria / BSACI guidance' },

  { id:'hodgkin-lymphoma', title:'Hodgkin lymphoma', category:'Haematology', icon:'🎗️',
    overview:'A cancer of the lymphatic system characterised by Reed-Sternberg cells, with a bimodal age distribution (young adults and older people). It is one of the most curable cancers, especially when caught early — making prompt recognition of persistent lymphadenopathy and "B symptoms" important.',
    features:[
      'Painless, progressive lymphadenopathy — classically firm, rubbery cervical or supraclavicular nodes',
      '"B symptoms": unexplained fever, drenching night sweats, and weight loss (>10% in 6 months) — important prognostically',
      'Other features: fatigue, pruritus, and (characteristically) pain in affected nodes after drinking alcohol',
      'Mediastinal involvement may cause cough, breathlessness, or superior vena cava obstruction',
      'Bimodal age peaks (young adults ~20s, and older adults); associations include Epstein-Barr virus and immunosuppression',
      'Diagnosis: lymph-node excision biopsy (Reed-Sternberg cells), with staging by CT/PET and bone-marrow assessment as needed'],
    management:[
      'Assess persistent or unexplained lymphadenopathy carefully — refer for urgent investigation when it is unexplained and persistent, especially with B symptoms',
      'Examine all node areas, liver and spleen, and check FBC, film, LDH and inflammatory markers; arrange imaging',
      'Refer on the suspected-cancer pathway for excision biopsy (not just fine-needle aspiration) to make the diagnosis',
      'Treatment is specialist (haemato-oncology): combination chemotherapy (e.g. ABVD) ± radiotherapy, guided by stage and prognostic factors — Hodgkin lymphoma is highly curable',
      'Manage treatment side effects and long-term/late effects (e.g. cardiovascular disease, second cancers, fertility, thyroid dysfunction) and arrange survivorship follow-up',
      'Discuss fertility preservation before treatment where relevant',
      'Provide psychological support and coordinate shared care',
      'Maintain vigilance for relapse and late effects on long-term follow-up'],
    referral:[
      'Unexplained lymphadenopathy (persistent, especially with B symptoms, or supraclavicular) → suspected haematological cancer pathway / urgent referral for excision biopsy (NICE NG12)',
      'Superior vena cava obstruction (facial/arm swelling, distended veins, breathlessness) → emergency admission',
      'Confirmed Hodgkin lymphoma → haemato-oncology MDT',
      'Fertility concerns before treatment → fertility services'],
    source:'NICE NG12 / NICE NG52 (lymphoma)' },

  { id:'hyperglycaemia', title:'Hyperglycaemia (high blood sugar)', category:'Endocrine & metabolic', icon:'🩸',
    overview:'A raised blood glucose level, usually in the context of diabetes. It ranges from mild, chronic hyperglycaemia (driving long-term complications) to acute hyperglycaemic emergencies — diabetic ketoacidosis (DKA) and the hyperosmolar hyperglycaemic state (HHS) — which are life-threatening and must be recognised promptly.',
    features:[
      'Symptoms of hyperglycaemia: polyuria, polydipsia, blurred vision, fatigue, and recurrent infections (e.g. thrush)',
      'May be the first presentation of diabetes (especially with weight loss in type 1) or reflect poor control/intercurrent illness in known diabetes',
      'Precipitants of acute deterioration: infection, missed medication/insulin, acute illness, steroids, and (for some) SGLT2 inhibitors (euglycaemic DKA)',
      'DIABETIC KETOACIDOSIS (more in type 1): hyperglycaemia (or euglycaemia), ketosis and acidosis — nausea/vomiting, abdominal pain, Kussmaul breathing, ketotic breath, dehydration (see DKA article)',
      'HYPEROSMOLAR HYPERGLYCAEMIC STATE (more in type 2, often older): marked hyperglycaemia with profound dehydration and reduced consciousness, but without significant ketoacidosis — develops over days',
      'Investigations: capillary/blood glucose, ketones (blood/urine), HbA1c, U&E, and assessment for a precipitant'],
    management:[
      'Assess for acute emergencies first: check ketones in any unwell hyperglycaemic patient — significant ketones/acidosis (DKA) or marked hyperglycaemia with dehydration/drowsiness (HHS) need emergency admission',
      'Treat the precipitant (e.g. infection) and ensure hydration',
      'For chronic hyperglycaemia in known diabetes: review adherence, diet, activity, and medication; optimise glucose-lowering therapy and HbA1c to individualised targets',
      'Reinforce "sick-day rules": never stop insulin, monitor glucose/ketones during illness, maintain fluids and carbohydrate, and seek help early',
      'For new significant hyperglycaemia, diagnose and classify diabetes and start appropriate management; suspect type 1 (and check ketones/refer urgently) in lean, young, or ketotic patients',
      'Educate on recognising and acting on high glucose/ketones, and on hypoglycaemia avoidance when intensifying treatment',
      'Manage the wider cardiovascular and complication risk in diabetes',
      'Arrange diabetes specialist input for type 1, recurrent emergencies, or difficult control'],
    referral:[
      'Suspected DKA (ketones + acidosis) or HHS (marked hyperglycaemia, dehydration, reduced consciousness) → emergency admission',
      'New-onset type 1 diabetes / ketosis → same-day specialist/paediatric assessment',
      'Recurrent hyperglycaemic emergencies or very poor control → diabetes specialist team',
      'Significant intercurrent illness with hyperglycaemia → assess and treat per sick-day guidance'],
    source:'NICE NG17/NG18/NG28 / JBDS guidance' },

  { id:'hyperhidrosis', title:'Hyperhidrosis (excessive sweating)', category:'Dermatology', icon:'💧',
    overview:'Excessive sweating beyond that needed for thermoregulation. Primary focal hyperhidrosis (axillae, palms, soles, face) is common, often starts in youth and is very distressing socially; secondary (generalised) hyperhidrosis points to an underlying cause that must be excluded. A stepwise treatment ladder helps most patients.',
    features:[
      'Primary focal hyperhidrosis: symmetrical excessive sweating of specific sites (armpits, palms, soles, face/scalp), typically starting in childhood/adolescence, absent during sleep, with a family history common',
      'Significant impact on work, relationships, clothing and self-esteem — it is a genuine quality-of-life problem, not "just sweating"',
      'SECONDARY (generalised) hyperhidrosis: widespread sweating, often with night sweats, prompting a search for an underlying cause',
      'Causes/red flags for secondary hyperhidrosis: hyperthyroidism, infection/TB, lymphoma and other malignancy, the menopause, diabetes/hypoglycaemia, anxiety, and drugs',
      'Night sweats with weight loss/fever/lymphadenopathy warrant investigation for serious disease (e.g. lymphoma, TB)',
      'Diagnosis is clinical; investigate secondary causes (e.g. TFTs, FBC, glucose) where the pattern is generalised or there are red flags'],
    management:[
      'Distinguish primary focal from secondary generalised hyperhidrosis; investigate and treat any underlying cause in secondary cases',
      'General advice: loose breathable clothing, absorbent dress shields, avoiding triggers, and emotional/psychological support',
      'First-line for focal hyperhidrosis: a topical aluminium chloride antiperspirant (applied at night) — effective for many, though it can irritate',
      'If topical treatment fails: options include iontophoresis (especially palms/soles), and an anticholinergic such as glycopyrronium (topical or oral) — weigh side effects',
      'Botulinum toxin injections are very effective for axillary (and palmar) hyperhidrosis — usually specialist-delivered and repeated periodically',
      'Refractory cases: refer to dermatology; further options include systemic agents and, rarely, surgery (e.g. endoscopic thoracic sympathectomy — with the risk of compensatory sweating)',
      'Address the substantial psychological impact and consider treating coexisting anxiety',
      'Provide information and a clear stepwise plan, reviewing response at each step'],
    referral:[
      'Secondary/generalised hyperhidrosis with red flags (night sweats + weight loss/fever/lymphadenopathy) → investigate urgently for an underlying cause (e.g. lymphoma/TB; consider NICE NG12 pathways)',
      'Focal hyperhidrosis refractory to topical treatment → dermatology (botulinum toxin, systemic options)',
      'Consideration of surgery (sympathectomy) → specialist',
      'Significant psychological impact → psychological support'],
    source:'NICE CKS — Hyperhidrosis' },

  { id:'hyperparathyroidism', title:'Hyperparathyroidism', category:'Endocrine & metabolic', icon:'🦴',
    overview:'Excess parathyroid hormone (PTH). Primary hyperparathyroidism (an autonomous parathyroid adenoma) is the commonest cause of hypercalcaemia in the community and is often found incidentally on blood tests. Secondary and tertiary forms arise in chronic kidney disease/vitamin D deficiency. Recognising the calcium-PTH pattern is key.',
    features:[
      'Often asymptomatic — detected as incidental hypercalcaemia on routine bloods',
      'Symptoms of hypercalcaemia ("bones, stones, groans and psychic moans"): bone pain/osteoporosis, renal stones, abdominal pain/constipation/nausea, polyuria/polydipsia, fatigue, low mood and cognitive symptoms',
      'PRIMARY hyperparathyroidism: raised (or inappropriately normal) PTH with raised calcium — usually a single parathyroid adenoma; complications include osteoporosis and renal stones/impairment',
      'SECONDARY: raised PTH with low/normal calcium, as a response to chronic kidney disease or vitamin D deficiency',
      'TERTIARY: autonomous PTH secretion (raised PTH and calcium) after long-standing secondary disease (e.g. in chronic kidney disease)',
      'Investigations: calcium (and ionised/corrected), PTH, phosphate, vitamin D, renal function, and (for primary) assessment of bone density and renal stones; exclude familial hypocalciuric hypercalcaemia'],
    management:[
      'Interpret calcium with a PTH level: raised calcium with raised/inappropriately normal PTH suggests primary hyperparathyroidism (whereas PTH is suppressed in malignancy-related hypercalcaemia)',
      'Exclude familial hypocalciuric hypercalcaemia (a benign mimic) with a urinary calcium/creatinine clearance ratio before referring for surgery',
      'Assess for complications: bone density (osteoporosis), renal function and renal stones',
      'Refer primary hyperparathyroidism to endocrinology/endocrine surgery — parathyroidectomy is curative and indicated for symptomatic disease, significant hypercalcaemia, osteoporosis, renal stones/impairment, or younger patients',
      'For conservative management (mild, asymptomatic): ensure good hydration, avoid factors that worsen calcium (e.g. thiazides, excess calcium/vitamin D supplements where inappropriate), and monitor calcium, renal function and bone density',
      'Treat severe symptomatic hypercalcaemia as an emergency (IV fluids; specialist treatment)',
      'For secondary/tertiary forms, treat the underlying cause (vitamin D deficiency) and manage within renal/CKD-MBD pathways',
      'Provide information and arrange appropriate monitoring/follow-up'],
    referral:[
      'Severe symptomatic hypercalcaemia (e.g. calcium very high, confusion, dehydration) → emergency admission',
      'Primary hyperparathyroidism → endocrinology/endocrine surgery (parathyroidectomy assessment)',
      'Hypercalcaemia with suppressed PTH (possible malignancy) → urgent investigation for underlying cancer (NICE NG12 as appropriate)',
      'Secondary/tertiary hyperparathyroidism in CKD → renal/endocrine'],
    source:'NICE NG132 (Hyperparathyroidism, primary)' },

  { id:'hyperthyroidism', title:'Overactive thyroid (hyperthyroidism)', category:'Endocrine & metabolic', icon:'🦋',
    overview:'Excess thyroid hormone, most often from Graves’ disease (autoimmune) or toxic nodular disease, causing a hypermetabolic state. It is common and very treatable, but the priorities are correct diagnosis, treating symptoms, recognising thyroid eye disease, and not missing the rare emergency of thyroid storm.',
    features:[
      'Hypermetabolic symptoms: weight loss despite a good appetite, heat intolerance, sweating, palpitations, tremor, anxiety/irritability, and loose stools',
      'Signs: tachycardia/atrial fibrillation, a fine tremor, warm moist skin, lid lag, and a goitre',
      'GRAVES’ disease (the commonest cause): may have specific features — thyroid eye disease (grittiness, proptosis, diplopia), pretibial myxoedema, and a diffuse goitre with a bruit',
      'Toxic multinodular goitre/toxic adenoma: nodular gland, often in older patients',
      'Atrial fibrillation, osteoporosis, and cardiac complications are important consequences, especially in older people',
      'Investigations: TFTs (suppressed TSH with raised free T4/T3), thyroid antibodies (TRAb for Graves’), and (where the cause is unclear) a radioiodine uptake scan'],
    management:[
      'Confirm with TFTs (suppressed TSH, raised free T4/T3) and determine the cause (TRAb antibodies; imaging if needed)',
      'Control symptoms quickly with a beta-blocker (e.g. propranolol) for tremor, palpitations and anxiety, unless contraindicated',
      'Refer to endocrinology for definitive management; antithyroid drugs (carbimazole — or propylthiouracil in early pregnancy) are typically started, by either a titration or "block-and-replace" regimen',
      'Warn patients on carbimazole about AGRANULOCYTOSIS: seek urgent help and a blood count for sore throat, fever or mouth ulcers, and stop the drug',
      'Definitive options for Graves’/nodular disease: radioiodine or surgery (thyroidectomy), with subsequent monitoring for hypothyroidism',
      'Manage thyroid eye disease (refer to ophthalmology; advise smoking cessation, which worsens it) and screen for/treat atrial fibrillation and osteoporosis risk',
      'In pregnancy/planning pregnancy, manage with specialist input (drug choice and monitoring differ)',
      'Recognise thyroid storm (fever, severe tachycardia/AF, agitation/delirium, vomiting) as an emergency'],
    referral:[
      'Suspected thyroid storm (hyperpyrexia, severe tachyarrhythmia, delirium) → emergency admission',
      'Confirmed hyperthyroidism → endocrinology for definitive treatment',
      'Thyroid eye disease (especially diplopia, proptosis, or any visual change) → ophthalmology (urgent if sight-threatening)',
      'Suspicious thyroid nodule with hyperthyroidism → assess per thyroid-cancer pathway (NICE NG12) as appropriate'],
    source:'NICE NG145 (Thyroid disease)' },

  { id:'hypoglycaemia', title:'Hypoglycaemia (low blood sugar)', category:'Endocrine & metabolic', icon:'🩸',
    overview:'A low blood glucose (typically <4 mmol/L, "four is the floor"), most often a complication of diabetes treatment (insulin or sulfonylureas). It can rapidly impair consciousness and cause harm, so prompt recognition and treatment are essential, as is identifying and preventing the cause to avoid recurrence.',
    features:[
      'Autonomic (early) symptoms: sweating, tremor, palpitations, hunger, and anxiety',
      'Neuroglycopenic symptoms: confusion, difficulty concentrating, slurred speech, behavioural change, drowsiness, seizures, and coma',
      'The commonest cause is diabetes treatment — insulin or sulfonylureas — especially with missed meals, exercise, alcohol, or renal impairment',
      'Impaired awareness of hypoglycaemia (loss of early warning symptoms) is a significant risk, often from recurrent hypos',
      'Non-diabetic causes (rarer): alcohol, critical illness, adrenal insufficiency, certain drugs, and (rare) insulinoma — investigate recurrent unexplained hypoglycaemia in a non-diabetic',
      'Confirm with a glucose measurement where possible, but do not delay treatment of a symptomatic patient'],
    management:[
      'Treat promptly: in a conscious, able-to-swallow patient, give 15–20 g of fast-acting carbohydrate (e.g. glucose tablets, juice/sugary drink), recheck glucose after ~15 minutes, and repeat if still low',
      'Once recovered, give a longer-acting carbohydrate (snack/meal) to prevent recurrence',
      'If the patient is unconscious/unable to swallow: this is an emergency — give intramuscular glucagon (if available) or IV glucose, place in the recovery position, and call 999',
      'Beware sulfonylurea-induced hypoglycaemia — it can be prolonged and recurrent, and usually warrants admission/observation',
      'Identify and address the cause: review insulin/sulfonylurea doses, timing, food, exercise, alcohol, and renal function; adjust the diabetes regimen to prevent recurrence',
      'Educate the patient/carers on recognising and treating hypos, carrying fast-acting carbohydrate, and glucagon use; address impaired awareness',
      'Advise on driving rules (DVLA) and hypoglycaemia, and document/flag recurrent hypos',
      'Investigate recurrent unexplained hypoglycaemia in a non-diabetic person (e.g. for insulinoma, adrenal insufficiency)'],
    referral:[
      'Severe hypoglycaemia (impaired consciousness/seizure), or any sulfonylurea-induced hypoglycaemia → emergency admission/observation',
      'Recurrent severe hypos or impaired awareness in diabetes → diabetes specialist team',
      'Recurrent unexplained hypoglycaemia in a non-diabetic → endocrinology (investigate for insulinoma/adrenal cause)',
      'Persistent hypoglycaemia despite treatment → urgent assessment'],
    source:'NICE NG17/NG28 / JBDS hypoglycaemia guidance' },

  { id:'hypoparathyroidism', title:'Hypoparathyroidism', category:'Endocrine & metabolic', icon:'🦴',
    overview:'Deficient parathyroid hormone (PTH), causing hypocalcaemia. The commonest cause is damage to or removal of the parathyroid glands during neck (especially thyroid) surgery. The clinical consequences stem from low calcium — from tingling and cramps to life-threatening tetany, laryngospasm and seizures.',
    features:[
      'Symptoms of hypocalcaemia: perioral and peripheral tingling/paraesthesia, muscle cramps, and carpopedal spasm (tetany)',
      'Signs: Chvostek’s sign (facial twitch on tapping the facial nerve) and Trousseau’s sign (carpal spasm with BP-cuff inflation)',
      'SEVERE hypocalcaemia: laryngospasm/stridor, seizures, prolonged QT interval and cardiac arrhythmia — an emergency',
      'Commonest cause is post-surgical (after thyroid/parathyroid/neck surgery — transient or permanent); other causes include autoimmune, congenital (e.g. DiGeorge), and magnesium disturbance',
      'Chronic hypoparathyroidism: low calcium, high phosphate, and low/inappropriately normal PTH; long-term complications include basal-ganglia calcification and cataracts',
      'Investigations: corrected calcium, PTH, phosphate, magnesium, vitamin D, renal function, and an ECG (QT interval)'],
    management:[
      'Confirm with corrected calcium and a PTH level (low/inappropriately normal PTH with hypocalcaemia), and check magnesium (low magnesium causes/aggravates it)',
      'Treat severe/symptomatic hypocalcaemia (tetany, seizures, laryngospasm, marked ECG changes) as an emergency — IV calcium (with cardiac monitoring) and admission',
      'Chronic management (specialist-guided): oral calcium and active vitamin D (e.g. alfacalcidol/calcitriol) to maintain calcium in the low-normal range, avoiding hypercalciuria/renal stones',
      'Correct coexisting magnesium deficiency, which must be addressed for calcium to normalise',
      'Monitor calcium, phosphate, renal function and urinary calcium; adjust treatment and watch for over-treatment (hypercalcaemia/renal complications)',
      'Recognise and manage post-thyroidectomy hypocalcaemia promptly (a common, often transient, postoperative scenario)',
      'Provide patient education on symptoms of low (and high) calcium and when to seek help',
      'Arrange endocrine follow-up; PTH replacement is available in specialist settings for difficult cases'],
    referral:[
      'Severe/symptomatic hypocalcaemia (tetany, seizures, laryngospasm, QT prolongation) → emergency admission for IV calcium',
      'Confirmed/chronic hypoparathyroidism → endocrinology for calcium/vitamin D management and monitoring',
      'Post-surgical hypocalcaemia → manage promptly ± specialist advice',
      'Difficult control or complications → endocrinology'],
    source:'NICE CKS / Society for Endocrinology — Hypoparathyroidism' },

  { id:'hypothyroidism', title:'Underactive thyroid (hypothyroidism)', category:'Endocrine & metabolic', icon:'🦋',
    overview:'Deficient thyroid hormone, most often from autoimmune thyroiditis (Hashimoto’s) or post-treatment of hyperthyroidism. It is common, especially in women and with age, and produces an insidious slowing of metabolism. It is straightforward to diagnose and treat, with levothyroxine, but needs correct dosing and monitoring.',
    features:[
      'Insidious symptoms: fatigue, weight gain, cold intolerance, constipation, dry skin, hair thinning, low mood, and cognitive slowing',
      'Signs: bradycardia, dry/coarse skin, a hoarse voice, delayed reflex relaxation, and sometimes a goitre',
      'Commonest cause is autoimmune (Hashimoto’s) thyroiditis; also after thyroid surgery/radioiodine, drugs (e.g. amiodarone, lithium), and (transiently) postpartum',
      'Subclinical hypothyroidism: a raised TSH with normal free T4 — manage based on symptoms, TSH level, antibodies, age and pregnancy plans',
      'MYXOEDEMA COMA (rare, severe): hypothermia, reduced consciousness, bradycardia and hypoventilation — a medical emergency, usually in older patients precipitated by illness',
      'Investigations: TFTs (raised TSH with low free T4 in primary hypothyroidism), and thyroid antibodies (TPO) to confirm autoimmune cause'],
    management:[
      'Confirm with TFTs (raised TSH, low free T4); check TPO antibodies to confirm autoimmune disease',
      'Treat overt hypothyroidism with levothyroxine, starting at an age/comorbidity-appropriate dose (lower and cautious in older patients/ischaemic heart disease), and titrate to symptoms and TSH',
      'Recheck TFTs about 6–8 weeks after starting/adjusting the dose, then periodically once stable (e.g. annually)',
      'Advise on taking levothyroxine consistently (on an empty stomach, separated from interfering drugs/supplements such as iron, calcium, PPIs)',
      'Subclinical hypothyroidism: consider treatment based on TSH level, symptoms, antibodies, age, and especially pregnancy/planning pregnancy; otherwise monitor',
      'Optimise thyroid status before and during pregnancy — requirements increase, and prompt dose adjustment with specialist input is important',
      'Recognise myxoedema coma as an emergency (admit; treated with thyroid hormone and supportive care)',
      'Review symptoms and adherence in those not responding, and reassess the diagnosis/dose'],
    referral:[
      'Myxoedema coma (hypothermia, reduced consciousness, in a hypothyroid patient) → emergency admission',
      'Hypothyroidism in pregnancy/planning pregnancy, or difficult-to-control disease → endocrinology',
      'Children, or secondary (pituitary) hypothyroidism → specialist',
      'Persistent symptoms despite biochemical correction → review/endocrinology'],
    source:'NICE NG145 (Thyroid disease)' }

  );
})();
